module divider_4bit(  
    input [3:0] dividend,  
    input [3:0] denominator,  
    output reg [3:0] quotient,  
    output reg [3:0] remainder  
);  
    always @(*) begin  
        if (denominator == 4'b0000) begin  
            quotient = 4'b0000;  
            remainder = 4'b0000;  
        end else begin  
            quotient = dividend / denominator;  
            remainder = dividend % denominator;  
        end  
    end  
endmodule
